// activeClass devolve "active" se a seção atual casa com a esperada.
// Pequeno helper para evitar if/else em cada link da NavBar.
func activeClass(current, expected string) string {
	if current == expected {
		return "active"
	}
	return ""
}

// currentPageFromTitle mapeia o título da página para o identificador
// curto usado pela NavBar. Usado quando o caller não passa explicitamente
// qual seção destacar.
func currentPageFromTitle(title string) string {
	switch title {
	case "Dashboard":
		return "dashboard"
	case "Tenants", "New Tenant":
		return "tenants"
	case "Users", "Invite User":
		return "users"
	case "Roles", "Role:":
		return "roles"
	case "Audit Log":
		return "audit"
	default:
		return ""
	}
}

